auth.verifyScript:
(function () {
 try {
 var currentUrl = location.href;
 if (currentUrl.indexOf('SSO/Main.aspx') !== -1) {
 var links = document.querySelectorAll('a');
 var foundTarget = false;
 for (var i = 0; i < links.length; i++) {
 var text = links[i].textContent.trim();
 if (text.indexOf('修課紀錄') !== -1 || text.indexOf('校務系統') !== -1) {
 foundTarget = true;
 break;
 }
 }
 var bridge = window.mobileApp || (window.webkit && window.webkit.messageHandlers && window.webkit.messageHandlers.mobileApp);
 if (bridge) {
 bridge.postMessage({ detail: { type: 'AUTH_SUCCESS' }});
 }
 }
 } catch (e) {}
})();

schedule.parseScript:
(function() {
 if (window.isProcessing) return;

 var container = document.getElementById('TabPanel2');
 var table = container ? container.querySelector('table') : null;
 if (!table) return;

 window.isProcessing = true;
 var result = [];
 var slotMap = ['1', '2', '3', '4', '5', '6', '7', '8'];

 for (var k = 0; k < slotMap.length; k++) {
 result.push({
 slot: slotMap[k],
 days: [{}, {}, {}, {}, {}]
 });
 }

 var rows = table.querySelectorAll('tbody tr');
 var dataIndex = 0;

 for (var i = 0; i < rows.length; i++) {
 var tr = rows[i];
 var cols = tr.querySelectorAll('td.course-cell');

 if (cols.length >= 5 && dataIndex < result.length) {
 var currentSlot = result[dataIndex];

 for (var d = 0; d < 5; d++) {
 var cell = cols[d];
 var div = cell.querySelector('.course-text');
 var text = div ? div.innerText.trim() : cell.innerText.trim();

 if (text.length > 0) {
 currentSlot.days[d] = {
 name: text,
 room: '',
 teacher: ''
 };
 }
 }
 dataIndex++;
 }
 }

 if (window.mobileApp) {
 window.mobileApp.postMessage({
 detail: { type: 'DATA_SUCCESS', payload: result }
 });
 }
})();

schedule.manualParseScript:
(function() {
 var table = document.querySelector('.table-list, #my-course-table, table');
 if (!table) {
 window.mobileApp.postMessage({ 
 detail: { type: 'ERROR', message: '畫面上找不到課表表格，請確認是否已點擊查詢。' } 
 });
 return;
 }

 if (window._hasSentSched) return;
 window._hasSentSched = true;

 var rows = table.querySelectorAll('tr:not(:first-child)');
 var result = [];

 // 亞昕系統通常前 8 列為課表
 for (var i = 0; i < 8; i++) {
 var tr = rows[i];
 var days = [];

 if (tr) {
 // 排除第一欄（節次標籤），抓取後續 7 欄（週一至週日）
 var tds = tr.querySelectorAll('td:not(:first-child)');
 for (var j = 0; j < 7; j++) {
 var c = tds[j];
 if (c && c.innerText.trim()) {
 var l = c.innerText.trim().split('\n');
 days.push({
 subject: l[0] || '',
 room: l[1] || '',
 teacher: l[2] || ''
 });
 } else {
 days.push({});
 }
 }
 } else {
 // 如果表格列數不足 8 列，補齊空列以符合 timeSlots 長度
 for (var k = 0; k < 7; k++) days.push({});
 }

 result.push({
 slot: (i + 1).toString(),
 days: days
 });
 }

 window.mobileApp.postMessage({ 
 detail: { type: 'DATA_SUCCESS', payload: result } 
 });
})();

score.switchScript:
(function() {
 var yr = document.querySelector('select[id*="ddl_year"], #ddl_year');
 var sm = document.querySelector('select[id*="ddl_sem"], #ddl_sem');
 var btn = document.querySelector('input[id*="btn_search"], #btn_search, #btnQuery');

 if (yr && sm && btn) {
 var targetYr = '{{TARGET_YEAR}}';
 var targetSm = '{{TARGET_SEM}}';


 if (yr.value !== targetYr || sm.value !== targetSm) {
 if (window._swLock && (Date.now() - window._swLock < 3000)) return;
 window._swLock = Date.now();

 yr.value = targetYr;
 sm.value = targetSm;


 setTimeout(function() {
 btn.click();
 }, 500);
 }
 }
})();

score.parseScript:
(function() {
 var findInAllContexts = function(selector, callback) {
 var result = callback(document.querySelector(selector), document);
 if (result) return result;

 var iframes = document.querySelectorAll('iframe');
 for (var i = 0; i < iframes.length; i++) {
 try {
 var fDoc = iframes[i].contentDocument || iframes[i].contentWindow.document;
 result = callback(fDoc.querySelector(selector), fDoc);
 if (result) return result;
 } catch (e) {}
 }
 return null;
 };

 var termLabel = findInAllContexts('select', function(sel, doc) {
 var allSelects = doc.querySelectorAll('select');
 for (var i = 0; i < allSelects.length; i++) {
 var opt = allSelects[i].options[allSelects[i].selectedIndex];
 if (opt && ["一上", "一下", "二上", "二下", "三上", "三下"].indexOf(opt.text) > -1) {
 return opt.text;
 }
 }
 return null;
 }) || "未知學期";

 var targetTable = findInAllContexts('table', function(table, doc) {
 var allTables = doc.querySelectorAll('table');
 for (var i = 0; i < allTables.length; i++) {
 if (allTables[i].innerText.indexOf('第一次評量') > -1) {
 return allTables[i];
 }
 }
 return null;
 });

 if (!targetTable) return;

 var res = [];
 var rows = targetTable.querySelectorAll('tr');
 rows.forEach(function(tr) {
 var tds = tr.querySelectorAll('td');
 if (tds.length >= 8) {
 var subject = tds[0].innerText.trim();
 var credit = tds[1].innerText.trim();
 var score = tds[tds.length - 1].innerText.trim();

 if (subject && subject !== "科目" && !isNaN(parseInt(credit))) {
 var scoreNum = parseInt(score);
 var isPass = !isNaN(scoreNum) ? scoreNum >= 60 : false;
 res.push({
 term: termLabel,
 subject: subject,
 credit: credit,
 score: score,
 isPass: isPass,
 status: isPass ? '及格' : '不及格'
 });
 }
 }
 });

 if (res.length > 0 && window.mobileApp) {
 window.mobileApp.postMessage({ 
 detail: { type: 'DATA_SUCCESS', payload: res } 
 });
 }
})();

news.webviewScript:
if (window._hasParsedNews) return;
var rows = document.querySelectorAll('.table-list tbody tr, table tr');
var payload = [];
if (rows.length > 0) {
 rows.forEach(function(tr) {
 var dateEl = tr.querySelector('.d-txt, .mdate') || (tr.cells ? tr.cells[0] : null);
 var titleContainer = tr.querySelector('.mtitle') || (tr.cells ? tr.cells[1] : null);
 var linkEl = titleContainer ? titleContainer.querySelector('a') : null;
 if (titleContainer) {
 var titleText = titleContainer.textContent.trim();
 if (titleText && titleText !== "標題" && titleText !== "主題") {
 payload.push({
 title: titleText,
 department: "校內公告",
 date: dateEl ? dateEl.textContent.trim() : '',
 link: linkEl ? linkEl.href : window.location.href
 });
 }
 }
 });
 if (payload.length > 0) {
 window._hasParsedNews = true;
 window.mobileApp.postMessage({ 
 detail: { 
 type: 'NEWS_SUCCESS', 
 payload: payload 
 } 
 });
 }
}
